class Solution {
    public int findMaxK(int[] nums) {
        Set<Integer> set = new HashSet<>();
        for (int num : nums) {
            set.add(num);
        }
        int k = -1;
        for (int num : nums) {
            if (set.contains(-num) && Math.abs(num) > k) {
                k = Math.abs(num);
            }
        }
        return k == -1 ? -1 : k;
    }
}
